import React from "react";
import api from "../api";

export default function DoctorDashboard() {

  async function loadAppointments() {

    const res =
      await api.get(
        "/doctor/appointments/today"
      );

    alert(
      JSON.stringify(res.data)
    );
  }

  async function updateConsultation() {

    await api.post(
      "/doctor/update-consultation"
    );

    alert("Consultation updated");
  }

  return (
    <div>

      <h2>Doctor Dashboard</h2>

      <button onClick={loadAppointments}>
        View Appointments
      </button>

      <button onClick={updateConsultation}>
        Update Consultation
      </button>

    </div>
  );
}
